                   let B  := {x  : ℝ | 2 < x ∧ x < 4}
                   ∀ x  : ℝ, x ∈ A ∩ (Bᶜ) ↔ -1 ≤ x ∧ x ≤ 2 := by

a99b73af.theorem:
theorem preimage_of_point  : 
  let f  : ℝ × ℝ → ℝ × ℝ  := fun p ↦ (p.1 + p.2, p.1 - p.2)
  ∃! p  : ℝ × ℝ, f p = (2, 0) ∧ p = (1, 1) := by

a7767ca1.theorem:
theorem intersection_distance_difference_16  : 
  let P  : ℝ × ℝ  := (1, 0)
  let A  : ℝ × ℝ  := (5, 3)
  let B  : ℝ × ℝ  := (0, -2)
  let distance (p₁ p₂  : ℝ × ℝ)  := Real.sqrt ((p₁.1 - p₂.1)^2 + (p₁.2 - p₂.2)^2)
  let AP  := distance A P
  let BP  := distance B P
  |AP - BP| = 5 - Real.sqrt 5 := by
